{
  description = "Rust WASM (wasm32-wasip2) project with Crane";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixpkgs-unstable";

    crane.url = "github:ipetkov/crane";
    crane.inputs.nixpkgs.follows = "nixpkgs";

    fenix.url = "github:nix-community/fenix";
    fenix.inputs.nixpkgs.follows = "nixpkgs";

    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, crane, fenix, flake-utils, ... }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = nixpkgs.legacyPackages.${system};

        # Build a combined toolchain that includes the wasip2 stdlib
        toolchain = with fenix.packages.${system};
          combine [
            stable.toolchain
            targets.wasm32-wasip2.stable.rust-std   # ← This is the key piece
          ];

        # Create a Crane instance that uses our custom toolchain
        craneLib = (crane.mkLib pkgs).overrideToolchain toolchain;

        # Common arguments for all builds
        commonArgs = {
          src = craneLib.cleanCargoSource ./.;

          strictDeps = true;

          # Force the target
          CARGO_BUILD_TARGET = "wasm32-wasip2";
        };

        # Build the actual crate
        my-crate = craneLib.buildPackage (commonArgs // {
          doCheck = false;
        });
      in
      {
        checks = {
          inherit my-crate;
        };

        packages.default = my-crate;

        # Dev shell
        devShells.default = craneLib.devShell {
          checks = self.checks.${system};

          packages = with pkgs; [
            wasmtime
            wasm-tools
            binaryen
          ];
        };
      }
    );
}
